use actix_web::{get, web, App, HttpResponse, HttpServer};
use std::fs;

#[get("/uploads/{filename}")]
async fn file_handler(filename: web::Path<String>) -> HttpResponse {
    match fs::read_to_string(&filename).await {
        Ok(contents) => HttpResponse::Ok().body(contents),
        Err(_) => HttpResponse::NotFound().body("File not found"),
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| App::new().service(file_handler))
        .bind("127.0.0.1:8000")?
        .run()
        .await
}
